import React, { useRef, useEffect, useState } from "react";
import { Line } from "react-chartjs-2";
import {
    Chart as ChartJS,
    LineElement,
    CategoryScale,
    LinearScale,
    PointElement,
    Tooltip,
    Filler,
    Legend
} from "chart.js";

ChartJS.register(LineElement, CategoryScale, LinearScale, PointElement, Tooltip, Filler, Legend);

const ChartComponent = ({ rawData, timeZone = 'Asia/Kolkata' }) => {
    const chartRef = useRef(null);
    const [gradient, setGradient] = useState(null);
    const [anomalyPositions, setAnomalyPositions] = useState([]);

    useEffect(() => {
        if (chartRef.current) {
            const ctx = chartRef.current.canvas.getContext('2d');
            const grad = ctx.createLinearGradient(0, 0, 0, 300);
            grad.addColorStop(0, "rgba(56, 189, 248, 0.4)"); // Neon Cyan strong
            grad.addColorStop(0.5, "rgba(56, 189, 248, 0.1)");
            grad.addColorStop(1, "rgba(56, 189, 248, 0)");
            setGradient(grad);
        }
    }, [rawData]);

    // This effect runs to calculate custom HTML overlay positions for anomalies
    useEffect(() => {
        if (chartRef.current && chartRef.current.getDatasetMeta) {
            const meta = chartRef.current.getDatasetMeta(1); // Anomaly dataset
            if (meta && meta.data) {
                const positions = meta.data.map((point, index) => {
                    if (rawData[index] && rawData[index].isAnomaly && !isNaN(point.x) && !isNaN(point.y)) {
                        return { x: point.x, y: point.y, key: index };
                    }
                    return null;
                }).filter(p => p !== null);
                setAnomalyPositions(positions);
            }
        }
    }, [rawData]);

    if (!rawData || rawData.length === 0) {
        return (
            <div className="h-full w-full flex items-center justify-center">
                <div className="animate-pulse flex space-x-2 items-center">
                    <div className="w-3 h-3 bg-blue-500 rounded-full shadow-[0_0_10px_#3b82f6]"></div>
                    <div className="w-3 h-3 bg-blue-400 rounded-full animation-delay-200 shadow-[0_0_10px_#60a5fa]"></div>
                    <div className="w-3 h-3 bg-blue-300 rounded-full animation-delay-400 shadow-[0_0_10px_#93c5fd]"></div>
                </div>
            </div>
        );
    }

    const labels = rawData.map(d => new Date(d.timestamp).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', timeZone }));
    const latencyData = rawData.map(d => d.latency);
    const anomalyPoints = rawData.map(d => d.isAnomaly ? d.latency : null);

    const data = {
        labels,
        datasets: [
            {
                label: "Latency",
                data: latencyData,
                borderColor: "#38bdf8", // Neon Cyan
                borderWidth: 3,
                tension: 0.4, // Smooth curved lines
                pointRadius: 0,
                pointHoverRadius: 6,
                pointHoverBackgroundColor: "#fff",
                pointHoverBorderColor: "#38bdf8",
                pointHoverBorderWidth: 2,
                backgroundColor: gradient || "rgba(56, 189, 248, 0.1)",
                fill: true,
            },
            {
                label: "Anomaly",
                data: anomalyPoints,
                borderColor: "transparent", // Hide the actual line
                backgroundColor: "transparent", // Hide default points, we'll draw custom HTML overlays
                pointRadius: 0,
                pointHoverRadius: 0,
                showLine: false,
            }
        ],
    };

    const options = {
        responsive: true,
        maintainAspectRatio: false,
        animation: {
            duration: 600,
            easing: 'easeOutQuart'
        },
        layout: {
            padding: {
                top: 15,
                right: 15,
                bottom: 10,
                left: 10
            }
        },
        interaction: {
            mode: 'index',
            intersect: false,
        },
        plugins: {
            legend: { display: false },
            tooltip: {
                backgroundColor: "rgba(15, 23, 42, 0.95)",
                titleColor: "#94a3b8",
                bodyColor: "#f8fafc",
                borderColor: "rgba(56, 189, 248, 0.3)",
                borderWidth: 1,
                padding: 12,
                titleFont: { size: 13, family: "sans-serif" },
                bodyFont: { size: 14, weight: "bold", family: "sans-serif" },
                displayColors: true,
                usePointStyle: true,
                boxPadding: 6,
                callbacks: {
                    label: (context) => {
                        if (context.datasetIndex === 1) return null; // Hide anomaly dataset from tooltip
                        const isAnomaly = rawData[context.dataIndex].isAnomaly;
                        let label = ` ${context.parsed.y} ms`;
                        if (isAnomaly) label += ' ⚠️ Anomaly';
                        return label;
                    }
                }
            }
        },
        scales: {
            x: {
                ticks: { color: "#64748b", maxTicksLimit: 6, font: { size: 11, family: "sans-serif" } },
                grid: { display: false }
            },
            y: {
                ticks: { color: "#64748b", font: { size: 11, family: "sans-serif" }, callback: val => val + "ms", padding: 8 },
                grid: { color: "rgba(255,255,255,0.03)", borderDash: [5, 5] },
                beginAtZero: true,
                suggestedMax: Math.max(...latencyData) * 1.2
            }
        }
    };

    return (
        <div className="h-full w-full relative group/chart">
            <div className="absolute inset-0 drop-shadow-[0_0_12px_rgba(56,189,248,0.4)] transition-all duration-300 group-hover/chart:drop-shadow-[0_0_18px_rgba(56,189,248,0.6)]">
                <Line ref={chartRef} data={data} options={options} />
            </div>
            {/* Custom Anomaly Glowing Dots Overlay */}
            {anomalyPositions.map((pos) => (
                <div
                    key={pos.key}
                    className="absolute pointer-events-none flex items-center justify-center z-20"
                    style={{
                        left: `${pos.x}px`,
                        top: `${pos.y}px`,
                        transform: 'translate(-50%, -50%)',
                        width: '28px',
                        height: '28px'
                    }}
                >
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-500 opacity-60"></span>
                    <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500 border-2 border-white shadow-[0_0_15px_rgba(239,68,68,1)]"></span>
                </div>
            ))}
        </div>
    );
};

export default ChartComponent;